import React, { useState, useEffect, useRef } from 'react';
import { BrowserRouter, Routes, Route, NavLink } from 'react-router-dom';
import MusicTrends    from './pages/MusicTrends';
import GenreBattle    from './pages/GenreBattle';
import MoodMap        from './pages/MoodMap';
import BopOrFlop      from './pages/BopOrFlop';
import ArtistExplorer from './pages/ArtistExplorer';
import './styles/global.css';

// ── Loading screen ─────────────────────────────────────────────────────────
function LoadingScreen({ onDone }) {
  const [phase, setPhase] = useState(0);
  // phase 0 = headphone animation
  // phase 1 = text appears
  // phase 2 = fade out

  useEffect(() => {
    const t1 = setTimeout(() => setPhase(1), 1200);
    const t2 = setTimeout(() => setPhase(2), 2800);
    const t3 = setTimeout(() => onDone(), 3400);
    return () => { clearTimeout(t1); clearTimeout(t2); clearTimeout(t3); };
  }, [onDone]);

  return (
    <div style={{
      position: 'fixed', inset: 0, zIndex: 9999,
      background: '#0a0a0a',
      display: 'flex', flexDirection: 'column',
      alignItems: 'center', justifyContent: 'center',
      gap: 24,
      opacity: phase === 2 ? 0 : 1,
      transition: 'opacity 0.6s ease',
      pointerEvents: phase === 2 ? 'none' : 'all',
    }}>

      {/* Headphone SVG with pulse animation */}
      <div style={{
        animation: 'headphonePop 0.8s cubic-bezier(0.34,1.56,0.64,1) forwards',
        opacity: 0,
      }}>
        <svg width="120" height="120" viewBox="0 0 120 120" fill="none" xmlns="http://www.w3.org/2000/svg">
          {/* Outer glow */}
          <circle cx="60" cy="60" r="58" fill="rgba(29,185,84,0.06)" stroke="rgba(29,185,84,0.2)" strokeWidth="1"/>
          {/* Headphone arc */}
          <path d="M25 60 C25 38 38 22 60 22 C82 22 95 38 95 60" stroke="#1db954" strokeWidth="5" strokeLinecap="round" fill="none"/>
          {/* Left ear cup */}
          <rect x="16" y="58" width="18" height="28" rx="9" fill="#1db954"/>
          {/* Right ear cup */}
          <rect x="86" y="58" width="18" height="28" rx="9" fill="#1db954"/>
          {/* Sound waves left */}
          <path d="M8 64 C4 68 4 74 8 78" stroke="#1db954" strokeWidth="2.5" strokeLinecap="round" fill="none" opacity="0.5"
            style={{animation:'wave 1.2s ease-in-out infinite', animationDelay:'0s'}}/>
          <path d="M3 58 C-3 66 -3 76 3 84" stroke="#1db954" strokeWidth="2" strokeLinecap="round" fill="none" opacity="0.3"
            style={{animation:'wave 1.2s ease-in-out infinite', animationDelay:'0.2s'}}/>
          {/* Sound waves right */}
          <path d="M112 64 C116 68 116 74 112 78" stroke="#1db954" strokeWidth="2.5" strokeLinecap="round" fill="none" opacity="0.5"
            style={{animation:'wave 1.2s ease-in-out infinite', animationDelay:'0.1s'}}/>
          <path d="M117 58 C123 66 123 76 117 84" stroke="#1db954" strokeWidth="2" strokeLinecap="round" fill="none" opacity="0.3"
            style={{animation:'wave 1.2s ease-in-out infinite', animationDelay:'0.3s'}}/>
          {/* Music note */}
          <text x="60" y="52" textAnchor="middle" fontSize="18" fill="#1db954" fontFamily="serif"
            style={{animation:'noteBounce 0.6s ease-in-out infinite alternate'}}>♪</text>
        </svg>
      </div>

      {/* Title */}
      <div style={{
        textAlign: 'center',
        opacity: phase >= 1 ? 1 : 0,
        transform: phase >= 1 ? 'translateY(0)' : 'translateY(16px)',
        transition: 'all 0.6s ease',
      }}>
        <div style={{
          fontFamily: 'Syne, sans-serif',
          fontSize: '2.4rem',
          fontWeight: 800,
          letterSpacing: '-1px',
          color: '#f0f0f0',
        }}>
          Spoti<span style={{ color: '#1db954' }}>lytics</span>
        </div>
        <div style={{
          fontSize: 13,
          color: '#888',
          marginTop: 6,
          letterSpacing: '2px',
          textTransform: 'uppercase',
        }}>
          Where Spotify Meets Analytics
        </div>
      </div>

      {/* Equalizer bars */}
      <div style={{
        display: 'flex', gap: 4, alignItems: 'flex-end', height: 32,
        opacity: phase >= 1 ? 1 : 0,
        transition: 'opacity 0.4s ease 0.3s',
      }}>
        {[1,2,3,4,5,6,7].map((_, i) => (
          <div key={i} style={{
            width: 4,
            background: '#1db954',
            borderRadius: 2,
            animation: `eq${i % 3} 0.${6+i}s ease-in-out infinite alternate`,
          }} />
        ))}
      </div>

      <style>{`
        @keyframes headphonePop {
          0%   { opacity:0; transform: scale(0.5) rotate(-10deg); }
          100% { opacity:1; transform: scale(1) rotate(0deg); }
        }
        @keyframes wave {
          0%,100% { opacity:0.2; }
          50%      { opacity:0.8; }
        }
        @keyframes noteBounce {
          from { transform: translateY(0); }
          to   { transform: translateY(-4px); }
        }
        @keyframes eq0 {
          from { height: 8px; }  to { height: 28px; }
        }
        @keyframes eq1 {
          from { height: 16px; } to { height: 10px; }
        }
        @keyframes eq2 {
          from { height: 22px; } to { height: 6px; }
        }
      `}</style>
    </div>
  );
}

// ── Nav ────────────────────────────────────────────────────────────────────
function Nav() {
  const [muted,   setMuted]   = useState(false);
  const [started, setStarted] = useState(false);
  const audioRef = useRef(null);

  useEffect(() => {
    const startMusic = () => {
  if (audioRef.current && !started) {
    setTimeout(() => {
      audioRef.current.volume = 0.15;
      audioRef.current.play().then(() => setStarted(true)).catch(() => {});
    }, 500);
  }
};
document.addEventListener('click', startMusic, { once: true });
document.addEventListener('keydown', (e) => {
  if (e.code === 'Space') startMusic();
}, { once: true });
  }, [started]);

  useEffect(() => {
    const handleKey = (e) => {
      if (e.code === 'Space' &&
          e.target.tagName !== 'INPUT' &&
          e.target.tagName !== 'TEXTAREA' &&
          e.target.tagName !== 'SELECT') {
        e.preventDefault();
        if (audioRef.current) {
          audioRef.current.muted = !audioRef.current.muted;
          setMuted(audioRef.current.muted);
        }
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, []);

  const toggleMute = () => {
    if (audioRef.current) {
      audioRef.current.muted = !muted;
      setMuted(!muted);
      if (!started) {
        audioRef.current.volume = 0.15;
        audioRef.current.play().then(() => setStarted(true)).catch(() => {});
      }
    }
  };

  return (
    <>
      <audio
        ref={audioRef}
        loop
        src="https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3"
        style={{ display: 'none' }}
      />
      <nav className="nav">
        <div className="nav-brand">
          <span className="nav-logo" style={{ animation: 'noteSpin 3s ease-in-out infinite' }}>♪</span>
          <span className="nav-title">Spotilytics</span>
        </div>

        <div className="nav-links">
          <NavLink to="/"                className={({isActive}) => isActive ? 'nav-link active' : 'nav-link'}>Music Trends</NavLink>
          <NavLink to="/genre-battle"    className={({isActive}) => isActive ? 'nav-link active' : 'nav-link'}>Genre Battle</NavLink>
          <NavLink to="/mood-map"        className={({isActive}) => isActive ? 'nav-link active' : 'nav-link'}>Mood Map</NavLink>
          <NavLink to="/artist-explorer" className={({isActive}) => isActive ? 'nav-link active' : 'nav-link'}>Artist Explorer</NavLink>
          <NavLink to="/bop-or-flop"     className={({isActive}) => isActive ? 'nav-link active' : 'nav-link'}>BopOrFlop</NavLink>
        </div>

        <button
          onClick={toggleMute}
          title={muted ? 'Unmute (Space)' : 'Mute (Space)'}
          style={{
            background: 'transparent',
            border: `1px solid ${muted ? 'rgba(255,255,255,0.08)' : 'rgba(29,185,84,0.3)'}`,
            borderRadius: 8,
            color: muted ? '#555' : '#1db954',
            fontSize: 16,
            padding: '4px 10px',
            cursor: 'pointer',
            transition: '0.2s',
            marginLeft: 8,
          }}
        >
          {muted ? '🔇' : '🎵'}
        </button>
      </nav>

      <style>{`
        @keyframes noteSpin {
          0%,100% { transform: rotate(0deg) scale(1); }
          25%      { transform: rotate(-15deg) scale(1.1); }
          75%      { transform: rotate(15deg) scale(1.1); }
        }
      `}</style>
    </>
  );
}

